var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"화력제압조, 정시에 도착했습니다.","JPN":"火力制圧班、時間通り到着しました。","ENG":"Firearm suppression team, right on time.","TWN":"火力壓制組已準時到達。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"저번에 들렀을 때보다 어수선하군요. 깔끔하게 치워 드릴까요?","JPN":"この前よりも散らかってますね。よし、きれいさっぱり片付てしまいましょう。","ENG":"Your office is messier than the last time we visited here. Want us to tidy it up for you?","TWN":"這裡比上次來的時候還要亂呢，要不要幫您收拾乾淨啊？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"괜찮으시다고요? 흐음...... 흠......","JPN":"片付けなくていいですって？　はぁ……そうですか……","ENG":"You don't want that. Hmm... Okay...","TWN":"不用嗎？嗯......哼......"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"이런, 이런, 이런. 종신계약. 그런 줄도 모르고.","JPN":"おやおやおや、これはこれは……終身契約。とんだ不意打ちですね。","ENG":"Uh-oh. A lifetime contract. I had no idea.","TWN":"哎呀，哎呀，哎呀，終身契約，我們居然都不知道。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"종신계약, 종신계약. 음, 무척 달달한 울림이군요. 버릇 들겠어요.","JPN":"終身契約、終身契約。うーむ、何と甘い響きでしょう。癖になってしまいそうです。","ENG":"Lifetime contract. Lifetime contract. Mm, that just rolls off my tongue. I can't stop saying it.","TWN":"終身契約，終身契約。嗯，真是無比甜美的發音，都快讓人上癮了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"그보다 역시 저희는 통하는 구석이 있군요.","JPN":"それにしても、私たちはどこか通じ合うところがあるようですね。","ENG":"Anyway, it seems we speak the same language.","TWN":"不說這個了，我們果然有共通之處。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"안 그래도 요새 사장님과 뜨거운 동료애를 쌓을 방법을 고민하던 참이었습니다.","JPN":"ちょうど社長と熱い友情を育む方法はないかと悩んでいたところだったんです。","ENG":"Lately I've been thinking about what to do to build rapport with you,","TWN":"本來我們最近就在煩惱，要怎麼和老闆建立火熱的友情呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"그런데 사장님께서 한 발 앞서 이런 얘기를 꺼내 주시다니......","JPN":"ちょうどそんなときに、社長の方からこんなお話をいただけるとは……","ENG":"and you beat me to it and make me such a great offer.","TWN":"但老闆居然比我們搶先一步說出這些話......"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"이거야말로 이심전심 아니겠습니까?","JPN":"これぞ以心伝心ってやつだと思いませんか？","ENG":"It's as if you read my mind.","TWN":"這不正是心心相印嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};